mapper.update:
UPDATE seat
SET `status` = 'RESERVED'
WHERE id = #{seatId}
  AND memberId = #{memberId}
  AND `status` = 'PENDING'

mapper.select:
SELECT COUNT(R.id)
FROM reservation AS R
INNER JOIN seat AS S ON R.seatId = S.id
WHERE R.memberId  = #{memberId}
  AND S.scheduleId = #{scheduleId}
  AND R.status     = 'CONFIRMED'

mapper.update:
UPDATE reservation
SET `status`    = 'CANCELLED',
    `updateDate` = NOW()
WHERE id = #{id}
  AND `memberId` = #{memberId}
